// Applying an effect to a target
void ApplyDamage(UAbilitySystemComponent* SourceASC, UAbilitySystemComponent* TargetASC,
    TSubclassOf<UGameplayEffect> DamageEffect, float Level)
{
    FGameplayEffectContextHandle Context = SourceASC->MakeEffectContext();
    Context.AddSourceObject(SourceASC->GetOwner());

    FGameplayEffectSpecHandle Spec = SourceASC->MakeOutgoingSpec(DamageEffect, Level, Context);
    if (Spec.IsValid())
    {
        TargetASC->ApplyGameplayEffectSpecToSelf(*Spec.Data.Get());
    }
}

