// Tag hierarchy matters
// Status.Debuff.Stun IS a child of Status.Debuff
FGameplayTag StunTag = FGameplayTag::RequestGameplayTag(FName("Status.Debuff.Stun"));
FGameplayTag DebuffTag = FGameplayTag::RequestGameplayTag(FName("Status.Debuff"));

// HasTag checks parents — returns true if ASC has Status.Debuff.Stun
bool bHasDebuff = ASC->HasMatchingGameplayTag(DebuffTag); // true!

// HasTagExact only matches exactly
bool bExact = ASC->HasMatchingGameplayTag(StunTag); // only if Stun specifically

// Adding a loose tag (persists until manually removed)
ASC->AddLooseGameplayTag(StunTag);

// Removing it
ASC->RemoveLooseGameplayTag(StunTag);

